CREATE TABLE IF NOT EXISTS "Products" (
	"prod_id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"prod_name" VARCHAR(255) NOT NULL,
	PRIMARY KEY("prod_id")
);




CREATE TABLE IF NOT EXISTS "Categories" (
	"cat_id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"cat_name" VARCHAR(255) NOT NULL,
	PRIMARY KEY("cat_id")
);




CREATE TABLE IF NOT EXISTS "Inventory" (
	"inv_id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"inv_prod" INTEGER NOT NULL,
	"inv_category" INTEGER NOT NULL,
	"inv_stock" INTEGER NOT NULL,
	"inv_price" DECIMAL NOT NULL,
	PRIMARY KEY("inv_id")
);


CREATE INDEX "Inventory_index_0"
ON "Inventory" ("inv_prod");
CREATE INDEX "Inventory_index_1"
ON "Inventory" ("inv_category");

CREATE TABLE IF NOT EXISTS "User" (
	"u_id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"u_password" VARCHAR(255) NOT NULL,
	"u_rol" INTEGER NOT NULL,
	PRIMARY KEY("u_id")
);


CREATE INDEX "User_index_0"
ON "User" ("u_rol");

CREATE TABLE IF NOT EXISTS "Role" (
	"r_id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"r_name" VARCHAR(255) NOT NULL,
	PRIMARY KEY("r_id")
);



ALTER TABLE "Categories"
ADD FOREIGN KEY("cat_id") REFERENCES "Inventory"("inv_category")
ON UPDATE NO ACTION ON DELETE NO ACTION;
ALTER TABLE "Products"
ADD FOREIGN KEY("prod_id") REFERENCES "Inventory"("inv_prod")
ON UPDATE NO ACTION ON DELETE NO ACTION;
ALTER TABLE "Role"
ADD FOREIGN KEY("r_id") REFERENCES "User"("u_rol")
ON UPDATE NO ACTION ON DELETE NO ACTION;